import sys

def prime(n):
    if n == 2:
        return True
    if n % 2 == 0 or n <= 1:
        return False

    sqr = int(n ** 0.5) + 1

    for divisor in range(3, sqr, 2):
        if n % divisor == 0:
            return False
    return True


def main():
    n = int(sys.stdin.readline().strip())
    for i in range(2, n):
        if prime(i):
            if prime(n - i):
                return i, n - i


if __name__ == "__main__":
    print(2)
    print(*main())
